import { registerModuleApi } from "../api/register-module-api";
import { createModuleApi } from "../api/create-module-api";
import { registerMusicBrowserSidebarButton } from "./add-music-browser-button";

type NinGhostsDebugGlobal = typeof globalThis & {
  ninGhosts?: ReturnType<typeof createModuleApi>;
};

export function registerModuleHooks(): void {
  registerDebugGlobal();

  Hooks.once("init", () => {
    registerModuleApiWhenAvailable("init");
    registerMusicBrowserSidebarButton();
  });
}

function registerDebugGlobal(): void {
  (globalThis as NinGhostsDebugGlobal).ninGhosts = createModuleApi();
}

function registerModuleApiWhenAvailable(phase: string): void {
  try {
    registerModuleApi();
  } catch (error) {
    console.warn(`[NIN Ghosts] API registration skipped during ${phase}.`, error);
  }
}
