import { openMusicBrowserApplication } from "../apps/music-browser/open-music-browser-application";
import { MODULE_ID } from "../constants";

const BUTTON_ACTION = `${MODULE_ID}.openMusicBrowser`;
const BUTTON_CLASS = "nin-ghosts-music-browser-button";
const DEBUG_GLOBAL = "ninGhostsDebug";
const PLAYLIST_TAB_SELECTORS = [
  "#playlists.sidebar-tab",
  "#sidebar section#playlists",
  "#sidebar .sidebar-tab[data-tab='playlists']",
  "#sidebar .sidebar-tab[data-tab='playlist']",
  "#sidebar section[data-tab='playlists']",
  "#sidebar section[data-tab='playlist']",
  "#sidebar .directory[data-document-name='Playlist']",
  "[data-application-part='playlists']",
];

export function registerMusicBrowserSidebarButton(): void {
  debug("Registering music browser sidebar hooks.");

  Hooks.on("renderPlaylistDirectory", (...args: unknown[]) => {
    debug("renderPlaylistDirectory fired.", describeArgs(args));
    addMusicBrowserButton(args);
  });

  Hooks.on("renderPlaylists", (...args: unknown[]) => {
    debug("renderPlaylists fired.", describeArgs(args));
    addMusicBrowserButton(args);
  });

  Hooks.on("renderSidebar", () => {
    debug("renderSidebar fired; scanning visible sidebar.");
    addMusicBrowserButtonToVisibleSidebar();
  });

  Hooks.on("renderSidebarTab", (...args: unknown[]) => {
    debug("renderSidebarTab fired.", describeArgs(args));

    if (isPlaylistSidebar(args)) {
      debug("renderSidebarTab matched playlist/sound tab.");
      addMusicBrowserButton(args);
    } else {
      debug("renderSidebarTab did not match playlist/sound tab.");
    }
  });

  Hooks.on("renderApplicationV2", (...args: unknown[]) => {
    if (isPlaylistSidebar(args)) {
      debug("renderApplicationV2 matched playlist/sound application.", describeArgs(args));
      addMusicBrowserButton(args);
      return;
    }

    const root = getRenderedElement(args);
    if (root?.id === "sidebar") {
      debug("renderApplicationV2 matched sidebar shell; scanning visible sidebar.");
      addMusicBrowserButtonToVisibleSidebar();
    }
  });

  Hooks.once("ready", () => {
    debug("ready hook fired; scanning visible sidebar and starting observer.");
    addMusicBrowserButtonToVisibleSidebar();
    observeSidebarForPlaylistTab();
  });
}

function addMusicBrowserButton(args: unknown[]): void {
  const root = getRenderedElement(args);

  if (!root) {
    debug("No rendered HTMLElement found for button insertion.", describeArgs(args));
    return;
  }

  if (isSidebarNavigationControl(root)) {
    debug("Skipping sidebar navigation control.", describeElement(root));
    return;
  }

  if (root.querySelector(`[data-action="${BUTTON_ACTION}"]`)) {
    debug("Button already exists in target root.", describeElement(root));
    return;
  }

  const button = document.createElement("button");
  button.className = BUTTON_CLASS;
  button.dataset["action"] = BUTTON_ACTION;
  button.type = "button";
  button.title = "Open NIN Ghosts music browser";
  button.innerHTML =
    '<i class="fa-solid fa-music" aria-hidden="true"></i><span>Ghosts Browser</span>';
  button.addEventListener("click", () => {
    void openMusicBrowserApplication();
  });

  const wrapper = document.createElement("div");
  wrapper.className = "nin-ghosts-music-browser-button-row";
  wrapper.append(button);

  const target = findButtonTarget(root);
  target.prepend(wrapper);
  debug("Inserted Ghosts Browser button.", {
    root: describeElement(root),
    target: describeElement(target),
  });
}

function addMusicBrowserButtonToVisibleSidebar(): void {
  const roots = new Set<HTMLElement>();
  const directoryRoot = getPlaylistDirectoryRoot();

  if (directoryRoot) {
    debug(
      "Found playlist directory root from game.playlists.directory.",
      describeElement(directoryRoot),
    );
    roots.add(directoryRoot);
  }

  for (const selector of PLAYLIST_TAB_SELECTORS) {
    const root = document.querySelector<HTMLElement>(selector);

    if (root) {
      if (isSidebarNavigationControl(root)) {
        debug("Visible sidebar selector matched navigation control; skipping.", {
          root: describeElement(root),
          selector,
        });
        continue;
      }

      debug("Visible sidebar selector matched.", {
        root: describeElement(root),
        selector,
      });
      roots.add(root);
    }
  }

  for (const root of roots) {
    addMusicBrowserButton([root]);
  }

  if (roots.size === 0) {
    debug("No visible playlist/sound sidebar target matched.", {
      checkedSelectors: PLAYLIST_TAB_SELECTORS,
      sidebarExists: Boolean(document.querySelector("#sidebar")),
    });
  }
}

function observeSidebarForPlaylistTab(): void {
  const sidebar = document.querySelector("#sidebar") ?? document.body;
  const observer = new MutationObserver(() => {
    addMusicBrowserButtonToVisibleSidebar();
  });

  observer.observe(sidebar, {
    childList: true,
    subtree: true,
  });
  debug("Sidebar observer started.", describeElement(sidebar));
}

function findButtonTarget(root: HTMLElement): HTMLElement {
  return (
    root.querySelector<HTMLElement>(".directory-header") ??
    root.querySelector<HTMLElement>(".sidebar-header") ??
    root.querySelector<HTMLElement>(".directory-controls") ??
    root.querySelector<HTMLElement>(".header-actions") ??
    root.querySelector<HTMLElement>("header") ??
    root
  );
}

function getRenderedElement(args: unknown[]): HTMLElement | undefined {
  for (const arg of args) {
    const element = unwrapElement(arg);

    if (element) {
      return element;
    }
  }

  return undefined;
}

function unwrapElement(value: unknown): HTMLElement | undefined {
  if (value instanceof HTMLElement) {
    return value;
  }

  if (!isElementWrapper(value)) {
    return undefined;
  }

  if (value.element instanceof HTMLElement) {
    return value.element;
  }

  if (value[0] instanceof HTMLElement) {
    return value[0];
  }

  return undefined;
}

function isElementWrapper(value: unknown): value is { 0?: unknown; element?: unknown } {
  return typeof value === "object" && value !== null;
}

function getPlaylistDirectoryRoot(): HTMLElement | undefined {
  const playlists = game?.playlists as { directory?: { element?: unknown } } | undefined;
  return unwrapElement(playlists?.directory?.element);
}

function isPlaylistSidebar(args: unknown[]): boolean {
  const root = getRenderedElement(args);

  if (root && isPlaylistRoot(root)) {
    return true;
  }

  return args.some((arg) => {
    if (typeof arg !== "object" || arg === null) {
      return false;
    }

    const constructorName = arg.constructor.name.toLowerCase();
    return constructorName.includes("playlist") || constructorName.includes("audio");
  });
}

function isPlaylistRoot(root: HTMLElement): boolean {
  const tab = root.dataset["tab"]?.toLowerCase();

  if (isSidebarNavigationControl(root)) {
    return false;
  }

  return (
    root.id === "playlists" ||
    tab === "playlists" ||
    tab === "playlist" ||
    root.classList.contains("playlists") ||
    root.dataset["documentName"] === "Playlist" ||
    root.matches(PLAYLIST_TAB_SELECTORS.join(","))
  );
}

function isSidebarNavigationControl(root: HTMLElement): boolean {
  return Boolean(
    root.closest("#sidebar-tabs, .sidebar-tabs, nav.tabs, menu.tabs") &&
    (root.matches("a, button, [role='tab'], [data-tab]") ||
      root.closest("a, button, [role='tab']")),
  );
}

function debug(message: string, data?: unknown): void {
  if (!isDebugEnabled()) {
    return;
  }

  if (data === undefined) {
    console.debug(`[NIN Ghosts] ${message}`);
    return;
  }

  console.debug(`[NIN Ghosts] ${message}`, data);
}

function isDebugEnabled(): boolean {
  return (globalThis as Record<string, unknown>)[DEBUG_GLOBAL] === true;
}

function describeArgs(args: unknown[]): unknown {
  return args.map((arg) => {
    if (arg instanceof HTMLElement) {
      return describeElement(arg);
    }

    if (isElementWrapper(arg)) {
      const element = unwrapElement(arg);

      return {
        constructor: arg.constructor.name,
        element: element ? describeElement(element) : undefined,
      };
    }

    return typeof arg;
  });
}

function describeElement(element: Element): Record<string, unknown> {
  return {
    className: element.className,
    id: element.id,
    tagName: element.tagName.toLowerCase(),
    tab: element instanceof HTMLElement ? element.dataset["tab"] : undefined,
  };
}
